import React, { useState, useEffect } from 'react';
import API from '../api/axios';

const ReportScreen = () => {
    const [complaints, setComplaints] = useState([]);
    const [filters, setFilters] = useState({
        department: '',
        programme: '',
        complaintType: '',
        status: '',
        assignee: ''
    });
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [users, setUsers] = useState([]);
    const [loading, setLoading] = useState(false);
    const [showReport, setShowReport] = useState(false);

    const typeOptions = ['PC Hardware', 'PC Software', 'Application Issues', 'Network', 'Electronics', 'Plumbing'];
    const statusOptions = ['Pending', 'Assigned', 'In-Progress', 'On-Hold', 'Completed'];

    useEffect(() => {
        fetchDepartments();
        fetchUsers();
    }, []);

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            console.error('Error fetching departments:', err);
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            console.error('Error fetching programmes:', err);
        }
    };

    const fetchUsers = async () => {
        try {
            const { data } = await API.get('/master/users');
            const staff = data.filter(u => ['Plumber', 'Electrician', 'Networking Staff', 'Software Developer'].includes(u.role));
            setUsers(staff);
        } catch (err) {
            console.error('Error fetching users:', err);
        }
    };

    const handleGenerateReport = async () => {
        setLoading(true);
        try {
            const { data } = await API.get('/complaints');
            let filtered = data;

            if (filters.department) {
                filtered = filtered.filter(c => c.department?._id === filters.department);
            }
            if (filters.programme) {
                filtered = filtered.filter(c => c.programme?._id === filters.programme);
            }
            if (filters.complaintType) {
                filtered = filtered.filter(c => c.complaintType === filters.complaintType);
            }
            if (filters.status) {
                filtered = filtered.filter(c => c.status === filters.status);
            }
            if (filters.assignee) {
                filtered = filtered.filter(c => c.assignedTo?._id === filters.assignee);
            }

            setComplaints(filtered);
            setShowReport(true);
        } catch (err) {
            alert('Error generating report');
        } finally {
            setLoading(false);
        }
    };

    const handlePrint = () => {
        window.print();
    };

    const handleExportCSV = () => {
        if (complaints.length === 0) {
            alert('No data to export');
            return;
        }

        const headers = ['Block', 'Room', 'Type', 'Status', 'Remarks', 'Raised By', 'Assigned To', 'Created Date'];
        const rows = complaints.map(c => [
            c.blockName,
            c.roomNumber,
            c.complaintType,
            c.status,
            c.complaintRemarks,
            c.user?.userName || '',
            c.assignedTo?.userName || 'Unassigned',
            new Date(c.createdAt).toLocaleDateString()
        ]);

        let csv = headers.join(',') + '\n';
        rows.forEach(row => {
            csv += row.map(val => `"${val}"`).join(',') + '\n';
        });

        const blob = new Blob([csv], { type: 'text/csv' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'complaints_report.csv';
        a.click();
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFilters({...filters, department: deptId, programme: ''});
        if (deptId) {
            fetchProgrammes(deptId);
        }
    };

    return (
        <div style={{ padding: '40px', color: 'white', background: '#0f172a', minHeight: '100vh' }}>
            <h2 style={{ fontSize: '2rem', marginBottom: '30px' }}>Complaint Details Report</h2>

            {!showReport ? (
                <div style={{ maxWidth: '600px', background: 'rgba(255,255,255,0.05)', padding: '30px', borderRadius: '10px', border: '1px solid #334155' }}>
                    <h3 style={{ marginBottom: '20px' }}>Report Filters</h3>

                    <div style={{ marginBottom: '15px' }}>
                        <label style={{ display: 'block', marginBottom: '5px' }}>Department</label>
                        <select 
                            value={filters.department}
                            onChange={handleDepartmentChange}
                            style={inputStyle}
                        >
                            <option value="">All Departments</option>
                            {departments.map(d => <option key={d._id} value={d._id}>{d.department}</option>)}
                        </select>
                    </div>

                    <div style={{ marginBottom: '15px' }}>
                        <label style={{ display: 'block', marginBottom: '5px' }}>Programme</label>
                        <select 
                            value={filters.programme}
                            onChange={e => setFilters({...filters, programme: e.target.value})}
                            style={inputStyle}
                        >
                            <option value="">All Programmes</option>
                            {programmes.map(p => <option key={p._id} value={p._id}>{p.programme}</option>)}
                        </select>
                    </div>

                    <div style={{ marginBottom: '15px' }}>
                        <label style={{ display: 'block', marginBottom: '5px' }}>Complaint Type</label>
                        <select 
                            value={filters.complaintType}
                            onChange={e => setFilters({...filters, complaintType: e.target.value})}
                            style={inputStyle}
                        >
                            <option value="">All Types</option>
                            {typeOptions.map(t => <option key={t} value={t}>{t}</option>)}
                        </select>
                    </div>

                    <div style={{ marginBottom: '15px' }}>
                        <label style={{ display: 'block', marginBottom: '5px' }}>Status</label>
                        <select 
                            value={filters.status}
                            onChange={e => setFilters({...filters, status: e.target.value})}
                            style={inputStyle}
                        >
                            <option value="">All Statuses</option>
                            {statusOptions.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                    </div>

                    <div style={{ marginBottom: '20px' }}>
                        <label style={{ display: 'block', marginBottom: '5px' }}>Assignee (Staff)</label>
                        <select 
                            value={filters.assignee}
                            onChange={e => setFilters({...filters, assignee: e.target.value})}
                            style={inputStyle}
                        >
                            <option value="">All Staff</option>
                            {users.map(u => <option key={u._id} value={u._id}>{u.userName}</option>)}
                        </select>
                    </div>

                    <button 
                        onClick={handleGenerateReport}
                        disabled={loading}
                        style={{
                            width: '100%',
                            padding: '12px',
                            background: 'linear-gradient(to right, #38bdf8, #818cf8)',
                            border: 'none',
                            borderRadius: '5px',
                            color: 'white',
                            fontWeight: 'bold',
                            cursor: 'pointer',
                            fontSize: '1rem'
                        }}
                    >
                        {loading ? 'Generating...' : 'Generate Report'}
                    </button>
                </div>
            ) : (
                <div>
                    <div style={{ marginBottom: '20px', display: 'flex', gap: '10px' }}>
                        <button 
                            onClick={() => setShowReport(false)}
                            style={{
                                padding: '10px 20px',
                                background: '#6b7280',
                                border: 'none',
                                borderRadius: '5px',
                                color: 'white',
                                cursor: 'pointer'
                            }}
                        >
                            Edit Filters
                        </button>
                        <button 
                            onClick={handlePrint}
                            style={{
                                padding: '10px 20px',
                                background: '#3b82f6',
                                border: 'none',
                                borderRadius: '5px',
                                color: 'white',
                                cursor: 'pointer'
                            }}
                        >
                            Print
                        </button>
                        <button 
                            onClick={handleExportCSV}
                            style={{
                                padding: '10px 20px',
                                background: '#10b981',
                                border: 'none',
                                borderRadius: '5px',
                                color: 'white',
                                cursor: 'pointer'
                            }}
                        >
                            Export CSV
                        </button>
                    </div>

                    <div style={{ background: 'rgba(255,255,255,0.05)', padding: '20px', borderRadius: '10px', border: '1px solid #334155', overflowX: 'auto' }}>
                        <h3 style={{ marginBottom: '20px' }}>Report Results ({complaints.length} records)</h3>
                        
                        {complaints.length === 0 ? (
                            <p>No complaints found matching the criteria</p>
                        ) : (
                            <table style={tableStyle}>
                                <thead>
                                    <tr style={{ background: '#1e293b' }}>
                                        <th>Block</th>
                                        <th>Room</th>
                                        <th>Type</th>
                                        <th>Status</th>
                                        <th>Remarks</th>
                                        <th>Raised By</th>
                                        <th>Assigned To</th>
                                        <th>Date</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {complaints.map(c => (
                                        <tr key={c._id} style={{ borderBottom: '1px solid #334155' }}>
                                            <td>{c.blockName}</td>
                                            <td>{c.roomNumber}</td>
                                            <td>{c.complaintType}</td>
                                            <td>
                                                <span style={{
                                                    padding: '3px 8px',
                                                    borderRadius: '3px',
                                                    background: getStatusColor(c.status),
                                                    fontSize: '0.85rem'
                                                }}>
                                                    {c.status}
                                                </span>
                                            </td>
                                            <td style={{ maxWidth: '150px', overflow: 'hidden', textOverflow: 'ellipsis' }}>{c.complaintRemarks}</td>
                                            <td>{c.user?.userName}</td>
                                            <td>{c.assignedTo?.userName || 'Unassigned'}</td>
                                            <td style={{ fontSize: '0.85rem' }}>{new Date(c.createdAt).toLocaleDateString()}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

const getStatusColor = (status) => {
    const colors = {
        'Pending': '#f59e0b',
        'Assigned': '#8b5cf6',
        'In-Progress': '#3b82f6',
        'On-Hold': '#ef4444',
        'Completed': '#10b981'
    };
    return colors[status] || '#6b7280';
};

const inputStyle = { 
    width: '100%', 
    padding: '10px', 
    marginTop: '5px',
    borderRadius: '5px', 
    border: '1px solid #334155', 
    background: '#1e293b', 
    color: 'white',
    boxSizing: 'border-box'
};

const tableStyle = {
    width: '100%',
    borderCollapse: 'collapse',
    fontSize: '0.85rem'
};

export default ReportScreen;
